import { AbilityBuilder, Ability, SubjectRawRule } from '@casl/ability';
import { customClaims } from '../models/interfaces'
import ModelRegistry from '../models'
const models = ModelRegistry.getInstance().getModels()

export function defineAbilitiesFor(role: customClaims): SubjectRawRule<string, unknown>[] {
  // const builder = new AbilityBuilder();
  const rawRules = [];

  // Add rules for each model using the toCASL() method
  Object.keys(models).forEach((key) => {
    const rules = new models[key]().toCASL(role);
    rawRules.push(...rules);
  });

  // Define abilities for the given role
  // builder.define(rawRules);

  return new Ability(rawRules);
};

